def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        if bins[i] <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bins[i]
        if ratio > 1:
            priorities[i] = ratio ** 2 + np.log1p(ratio)
        elif ratio == 1:
            priorities[i] = 0.5
        else:
            val = 0
            for j in range(1, 5):
                val += ((-1) ** (j+1)) * (ratio ** j) / j
            priorities[i] = val if val > 0 else 0.1
        if bins[i] < item * 2:
            priorities[i] *= 1.5
        elif bins[i] > item * 5:
            priorities[i] /= 2
    return priorities
